import 'package:connectivity_plus/connectivity_plus.dart'; import 'package:injectable/injectable.dart'; @singleton class ConnectivityChecker { Future<bool> isConnected() async { final r = await Connectivity().checkConnectivity(); return r.first != ConnectivityResult.none; } Stream<bool> get stream => Connectivity().onConnectivityChanged.map((r) => r.first != ConnectivityResult.none); Future<bool> isWifi() async { final r = await Connectivity().checkConnectivity(); return r.first == ConnectivityResult.wifi; } }